window.getI18nString = function (key) {
  const lang = document.documentElement.lang === "es" ? "es" : "en";
  const dict = translations[lang] || translations.en;
  return dict[key] || "";
};

const storageKey = "portfolio-language";

function getInitialLanguage() {
  const stored = window.localStorage.getItem(storageKey);
  if (stored === "en" || stored === "es") return stored;
  return navigator.language.toLowerCase().startsWith("es") ? "es" : "en";
}

function applyLanguage(lang) {
  const dict = translations[lang] || translations.en;
  document.documentElement.lang = lang;

  document.querySelectorAll("[data-i18n]").forEach((node) => {
    const key = node.getAttribute("data-i18n");
    if (key && dict[key]) node.textContent = dict[key];
  });

  document.querySelectorAll("[data-i18n-attr]").forEach((node) => {
    const pairs = node.getAttribute("data-i18n-attr");
    if (!pairs) return;
    pairs.split(";").forEach((pair) => {
      const [attr, key] = pair.split(":");
      if (attr && key && dict[key]) {
        node.setAttribute(attr.trim(), dict[key]);
      }
    });
  });

  const toggle = document.getElementById("langToggle");
  if (toggle) {
    toggle.textContent = dict.toggleText;
    toggle.setAttribute("aria-label", dict.toggleAria);
  }

  const resumePrint = document.querySelector(".closing-resume-print");
  if (resumePrint) {
    resumePrint.setAttribute("href", lang === "es" ? "resume/es.html" : "resume/en.html");
  }

  const coverPrint = document.querySelector(".closing-cover-print");
  if (coverPrint) {
    coverPrint.setAttribute("href", lang === "es" ? "resume/cover-letter-es.html" : "resume/cover-letter-en.html");
  }

  if (typeof window.renderRoadmap === "function") {
    window.renderRoadmap();
  }
}

function initI18n() {
  let currentLanguage = getInitialLanguage();
  applyLanguage(currentLanguage);

  const toggle = document.getElementById("langToggle");
  if (!toggle) return;

  toggle.addEventListener("click", () => {
    currentLanguage = currentLanguage === "en" ? "es" : "en";
    window.localStorage.setItem(storageKey, currentLanguage);
    applyLanguage(currentLanguage);
  });
}

document.addEventListener("DOMContentLoaded", initI18n);
